#include <stdio.h>
#include <string.h>

// Note: In production, use OpenSSL or mhash library
// This is a conceptual demonstration

/* MD5 Context Structure */
typedef struct {
    unsigned int count[2];
    unsigned int state[4];
    unsigned char buffer[64];
} MD5_CTX;

/* MD5 Constants */
#define F(x, y, z) ((x & y) | (~x & z))
#define G(x, y, z) ((x & z) | (y & ~z))
#define H(x, y, z) (x ^ y ^ z)
#define I(x, y, z) (y ^ (x | ~z))

void MD5Init(MD5_CTX *context) {
    context->count[0] = context->count[1] = 0;
    context->state[0] = 0x67452301;
    context->state[1] = 0xefcdab89;
    context->state[2] = 0x98badcfe;
    context->state[3] = 0x10325476;
}

/* Example usage would call MD5Update and MD5Final */
int main() {
    MD5_CTX context;
    MD5Init(&context);
    printf("MD5 initialized - state: %08x %08x %08x %08x\n",
           context.state[0], context.state[1], 
           context.state[2], context.state[3]);
    printf("WARNING: MD5 is cryptographically broken!\n");
    printf("Use SHA-256 or SHA-3 for security.\n");
    return 0;
}

import javax.crypto.Mac;
import javax.crypto.Cipher;
import javax.crypto.spec.SecretKeySpec;
import javax.crypto.spec.IvParameterSpec;
import java.security.InvalidKeyException;
import java.security.NoSuchAlgorithmException;

public class MACComparison {

    // HMAC-SHA256
    public static String generateHMAC(String message, String key) 
            throws NoSuchAlgorithmException, InvalidKeyException {
        Mac mac = Mac.getInstance("HmacSHA256");
        SecretKeySpec secretKey = new SecretKeySpec(key.getBytes(), "HmacSHA256");
        mac.init(secretKey);
        byte[] hmacBytes = mac.doFinal(message.getBytes());
        return bytesToHex(hmacBytes);
    }

    // CMAC (using AES)
    public static String generateCMAC(String message, String key) 
            throws Exception {
        // CMAC uses AES in CBC mode with proper key derivation
        Cipher cipher = Cipher.getInstance("AES/ECB/NoPadding");
        SecretKeySpec secretKey = new SecretKeySpec(key.getBytes(), "AES");
        cipher.init(Cipher.ENCRYPT_MODE, secretKey);

        // Pad message to 16-byte block
        byte[] messageBytes = message.getBytes();
        byte[] padded = new byte[16];
        System.arraycopy(messageBytes, 0, padded, 0, 
                        Math.min(messageBytes.length, 16));

        byte[] cmacBytes = cipher.doFinal(padded);
        return bytesToHex(cmacBytes);
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    public static void main(String[] args) throws Exception {
        String message = "Important Message";
        String key = "my_secret_key_12345678901234";

        String hmac = generateHMAC(message, key);
        String cmac = generateCMAC(message, key);

        System.out.println("HMAC-SHA256: " + hmac);
        System.out.println("CMAC-AES:    " + cmac);
        System.out.println("Both provide integrity + authentication");
    }
}
